function findFirstVisibleIndex(
  positions: Position[],
  scrollTop: number
): number {
  // 边界情况：空列表
  if (positions.length === 0) {
    return -1;
  }
  // 边界情况：scrollTop为负数或0，第一项可见
  if (scrollTop <= 0) {
    return 0;
  }
  let left = 0;
  let right = positions.length - 1;
  let result = positions.length - 1; // 默认返回最后一项
  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    const position = positions[mid];
    // 查找第一个bottom > scrollTop的元素
    if (position.bottom > scrollTop) {
      result = mid;
      right = mid - 1; // 继续向左查找是否有更早的可见项
    } else {
      left = mid + 1;
    }
  }
