class TaskScheduler {
  private taskQueue: Task[] = [];
  private isRunning: boolean = false;
  private frameDeadline: number = 0;
  private readonly FRAME_BUDGET = 16;
  addTask(task: Task): void {
    const insertIndex = this.taskQueue.findIndex(t => t.priority > task.priority);
    if (insertIndex === -1) {
      this.taskQueue.push(task);
    } else {
      this.taskQueue.splice(insertIndex, 0, task);
    }
    if (!this.isRunning) this.start();
  }
  start(): void {
    if (this.isRunning) return;
    this.isRunning = true;
    this.scheduleNextFrame();
  }
  private scheduleNextFrame(): void {
    if (typeof scheduler !== 'undefined' && scheduler.postTask) {
      scheduler.postTask(() => this.runFrame(), { priority: 'user-blocking' });
    } else {
      requestAnimationFrame(() => this.runFrame());
    }
  }
  private runFrame(): void {
    this.frameDeadline = performance.now() + this.FRAME_BUDGET;
    while (!this.shouldYield() && this.taskQueue.length > 0) {
      const task = this.taskQueue[0];
      if (task.execute()) {
        this.taskQueue.shift();
      }
    }
    if (this.taskQueue.length > 0) {
      this.scheduleNextFrame();
    } else {
      this.isRunning = false;
    }
  }
  private shouldYield(): boolean {
    return performance.now() >= this.frameDeadline;
  }
}
